patch:
diff --git a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
index dad0d1e9ef55..e23d90c96574 100644
--- a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
+++ b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
@@ -21065,9 +21065,13 @@ bool BoUpSLP::BlockScheduling::extendSchedulingRegion(
          "lower end.");
   assert(I->getParent() == ScheduleEnd->getParent() &&
          "Instruction is in wrong basic block.");
-  initScheduleData(ScheduleEnd, I->getNextNode(), LastLoadStoreInRegion,
+  Instruction *NextI = I->getNextNode();
+  // Don't try to extend scheduling region beyond terminators.
+  if (!NextI)
+    return false;
+  initScheduleData(ScheduleEnd, NextI, LastLoadStoreInRegion,
                    nullptr);
-  ScheduleEnd = I->getNextNode();
+  ScheduleEnd = NextI;
   assert(ScheduleEnd && "tried to vectorize a terminator?");
   LLVM_DEBUG(dbgs() << "SLP:  extend schedule region end to " << *I << "\n");
   return true;

